<?php
namespace App\Models\Purchases; use App\Models\User; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\SoftDeletes;
#[Fillable(['company_id','branch_id','warehouse_id','supplier_id','purchase_order_id','invoice_number','supplier_invoice_number','supplier_invoice_date','financial_year','status','currency','place_of_supply_state_code','reverse_charge','subtotal','discount_total','taxable_total','input_cgst','input_sgst','input_igst','input_cess','grand_total','paid_total','outstanding_total','due_date','notes','created_by','approved_by','approved_at'])]
class PurchaseInvoice extends Model {use SoftDeletes;protected function casts():array{return ['supplier_invoice_date'=>'date','due_date'=>'date','approved_at'=>'datetime','reverse_charge'=>'boolean','subtotal'=>'decimal:2','discount_total'=>'decimal:2','taxable_total'=>'decimal:2','input_cgst'=>'decimal:2','input_sgst'=>'decimal:2','input_igst'=>'decimal:2','input_cess'=>'decimal:2','grand_total'=>'decimal:2','paid_total'=>'decimal:2','outstanding_total'=>'decimal:2'];}public function supplier():BelongsTo{return $this->belongsTo(Supplier::class);}public function items():HasMany{return $this->hasMany(PurchaseInvoiceItem::class);}public function payments():HasMany{return $this->hasMany(SupplierPaymentAllocation::class);}}
